import { useState, useCallback, useRef, useEffect } from 'react';

interface UseSpeechToTextOptions {
  lang?: string;
  continuous?: boolean;
  interimResults?: boolean;
  onResult?: (transcript: string, isFinal: boolean) => void;
  onError?: (error: string) => void;
}

interface UseSpeechToTextReturn {
  isListening: boolean;
  transcript: string;
  startListening: () => void;
  stopListening: () => void;
  resetTranscript: () => void;
  isSupported: boolean;
  error: string | null;
}

// Check if SpeechRecognition is available
const getSpeechRecognition = () => {
  if (typeof window === 'undefined') return null;
  return (window as unknown as { SpeechRecognition: unknown; webkitSpeechRecognition: unknown }).SpeechRecognition || 
         (window as unknown as { SpeechRecognition: unknown; webkitSpeechRecognition: unknown }).webkitSpeechRecognition;
};

export const useSpeechToText = (options: UseSpeechToTextOptions = {}): UseSpeechToTextReturn => {
  const {
    lang = 'ja-JP',
    continuous = false,
    interimResults = true,
    onResult,
    onError,
  } = options;

  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [error, setError] = useState<string | null>(null);
  const recognitionRef = useRef<unknown>(null);

  const SpeechRecognition = getSpeechRecognition();
  const isSupported = !!SpeechRecognition;

  useEffect(() => {
    if (!isSupported) return;

    const recognition = new (SpeechRecognition as { new (): any })();
    recognition.lang = lang;
    recognition.continuous = continuous;
    recognition.interimResults = interimResults;

    recognition.onstart = () => {
      setIsListening(true);
      setError(null);
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    recognition.onerror = (event: { error: string }) => {
      let errorMessage = 'Láŧi nháš­n diáŧn giáŧng nÃģi';
      
      switch (event.error) {
        case 'no-speech':
          errorMessage = 'KhÃīng phÃĄt hiáŧn giáŧng nÃģi';
          break;
        case 'audio-capture':
          errorMessage = 'KhÃīng tÃŽm thášĨy microphone';
          break;
        case 'not-allowed':
          errorMessage = 'Quyáŧn truy cáš­p microphone báŧ táŧŦ cháŧi';
          break;
        case 'network':
          errorMessage = 'Láŧi kášŋt náŧi mášĄng';
          break;
        case 'aborted':
          errorMessage = 'ÄÃĢ dáŧŦng nháš­n diáŧn';
          break;
      }
      
      setError(errorMessage);
      setIsListening(false);
      onError?.(errorMessage);
    };

    recognition.onresult = (event: { resultIndex: number, results: Array<{ isFinal: boolean, [key: number]: { transcript: string } }> }) => {
      let finalTranscript = '';
      let interimTranscript = '';

      for (let i = event.resultIndex; i < event.results.length; i++) {
        const result = event.results[i];
        if (result.isFinal) {
          finalTranscript += result[0].transcript;
        } else {
          interimTranscript += result[0].transcript;
        }
      }

      const currentTranscript = finalTranscript || interimTranscript;
      setTranscript(currentTranscript);
      onResult?.(currentTranscript, !!finalTranscript);
    };

    recognitionRef.current = recognition;

    return () => {
      recognition.abort();
    };
  }, [isSupported, lang, continuous, interimResults, onResult, onError, SpeechRecognition]);

  const startListening = useCallback(() => {
    if (!isSupported) {
      setError('TrÃŽnh duyáŧt khÃīng háŧ tráŧĢ nháš­n diáŧn giáŧng nÃģi');
      return;
    }

    setTranscript('');
    setError(null);
    
    try {
      (recognitionRef.current as { start: () => void })?.start();
    } catch (e) {
      // Already started
    }
  }, [isSupported]);

  const stopListening = useCallback(() => {
    try {
      (recognitionRef.current as { stop: () => void })?.stop();
    } catch (e) {
      // Already stopped
    }
    setIsListening(false);
  }, []);

  const resetTranscript = useCallback(() => {
    setTranscript('');
    setError(null);
  }, []);

  return {
    isListening,
    transcript,
    startListening,
    stopListening,
    resetTranscript,
    isSupported,
    error,
  };
};

