interface Folder {
  id: string;
  name: string;
  description: string | null;
  icon: string;
  color: string;
  parent_id: string | null;
  module_id: string | null;
  order_index: number;
  children?: Folder[];
}

const defaultIcons = ['ð', 'ð', 'ð', 'ð', 'âïļ', 'ðŊ', 'â­', 'ðĄ'];
const defaultColors = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#14b8a6'];

const FolderNode: React.FC<{
  folder: Folder;
  onEdit: (folder: Folder) => void;
  onDelete: (id: string) => void;
  onCreateChild: (parentId: string) => void;
  level: number;
}> = ({ folder, onEdit, onDelete, onCreateChild, level }) => {
  const [isExpanded, setIsExpanded] = useState(true);
  const hasChildren = folder.children && folder.children.length > 0;

  return (
    <div className="space-y-1">
      <div
        className="flex items-center gap-2 p-2 rounded-lg hover:bg-muted group"
        style={{ paddingLeft: `${level * 1.5}rem` }}
      >
        {hasChildren && (
          <button
            onClick={() => setIsExpanded(!isExpanded)}
            className="p-0.5 hover:bg-background rounded"
          >
            {isExpanded ? (
              <ChevronDown className="h-4 w-4" />
            ) : (
              <ChevronRight className="h-4 w-4" />
            )}
          </button>
        )}
        {!hasChildren && <div className="w-5" />}
        
<div
          className="p-1.5 rounded text-lg"
          style={{ backgroundColor: folder.color }}
        >
          {folder.icon}
        </div>
        
        <div className="flex-1 min-w-0">
          <p className="font-medium truncate">{folder.name}</p>
          {folder.description && (
            <p className="text-xs text-muted-foreground truncate">
              {folder.description}
            </p>
          )}
        </div>
        
        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => onCreateChild(folder.id)}
          >
            <FolderPlus className="h-3 w-3" />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => onEdit(folder)}
          >
            <Edit className="h-3 w-3" />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            onClick={() => onDelete(folder.id)}
          >
            <Trash2 className="h-3 w-3" />
          </Button>
        </div>
      </div>
      
      {hasChildren && isExpanded && (
        <div className="space-y-1">
          {folder.children!.map((child) => (
            <FolderNode
              key={child.id}
              folder={child}
              onEdit={onEdit}
              onDelete={onDelete}
              onCreateChild={onCreateChild}
              level={level + 1}
            />
          ))}
        </div>
      )}
    </div>
  );
};

export const FolderManager = () => {
  const { user } = useAuth();
  const { toast } = useToast();
  const [searchParams] = useSearchParams();
  const moduleId = searchParams.get('module');
  
  const [folders, setFolders] = useState<Folder[]>([]);
  const [loading, setLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingFolder, setEditingFolder] = useState<Folder | null>(null);
  const [parentIdForNew, setParentIdForNew] = useState<string | null>(null);
  
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    icon: 'ð',
    color: '#10b981',
    parent_id: null as string | null,
  });

  useEffect(() => {
    if (user) {
      fetchFolders();
    }
  }, [user, moduleId, fetchFolders]);

  const fetchFolders = useCallback(async () => {
    try {
      let query = (supabase as unknown as { from: (s: string) => { select: (s: string) => { eq: (f: string, v: string) => { order: (s: string, o: { ascending: boolean }) => any } } } })
        .from('vocabulary_folders')
        .select('*')
        .eq('user_id', user!.id)
        .order('order_index', { ascending: true });

      if (moduleId) {
        query = query.eq('module_id', moduleId);
      }

      const { data, error } = await query;

      if (error) throw error;
      
      // Build tree structure
      const folderMap = new Map<string, Folder>();
      const rootFolders: Folder[] = [];

      (data as Folder[])?.forEach((folder: Folder) => {
        folderMap.set(folder.id, { ...folder, children: [] } as Folder);
      });

      (data as Folder[])?.forEach((folder: Folder) => {
        const folderNode = folderMap.get(folder.id)!;
        if (folder.parent_id) {
          const parent = folderMap.get(folder.parent_id);
          if (parent) {
            parent.children!.push(folderNode);
          }
        } else {
          rootFolders.push(folderNode);
        }
      });

      setFolders(rootFolders);
    } catch (error) {
      console.error('Error fetching folders:', error);
      toast({
        title: 'Láŧi',
        description: 'KhÃīng tháŧ tášĢi danh sÃĄch folder',
        variant: 'destructive',
      });
    } finally {
      setLoading(false);
    }
  }, [user, moduleId, toast]);

  const handleCreateOrUpdate = async () => {
    if (!formData.name.trim()) {
      toast({
        title: 'Láŧi',
        description: 'Vui lÃēng nháš­p tÃŠn folder',
        variant: 'destructive',
      });
      return;
    }

    try {
      if (editingFolder) {
        const { error } = await supabase
          .from('vocabulary_folders')
          .update({
            name: formData.name,
            description: formData.description || null,
            icon: formData.icon,
            color: formData.color,
            parent_id: formData.parent_id,
          })
          .eq('id', editingFolder.id);

        if (error) throw error;

        toast({ title: 'ThÃ nh cÃīng', description: 'ÄÃĢ cáš­p nháš­t folder' });
      } else {
        const { error } = await supabase
          .from('vocabulary_folders')
          .insert({
            user_id: user!.id,
            module_id: moduleId || null,
            name: formData.name,
            description: formData.description || null,
            icon: formData.icon,
            color: formData.color,
            parent_id: parentIdForNew || formData.parent_id,
            order_index: 0,
          });

        if (error) throw error;

        toast({ title: 'ThÃ nh cÃīng', description: 'ÄÃĢ tášĄo folder máŧi' });
      }

      setIsDialogOpen(false);
      resetForm();
      fetchFolders();
    } catch (error) {
      console.error('Error saving folder:', error);
      toast({
        title: 'Láŧi',
        description: 'KhÃīng tháŧ lÆ°u folder',
        variant: 'destructive',
      });
    }
  };

  const handleDelete = async (folderId: string) => {
    if (!confirm('BášĄn cÃģ chášŊc muáŧn xÃģa folder nÃ y? CÃĄc folder con cÅĐng sáš― báŧ xÃģa.')) return;

    try {
      const { error } = await supabase
        .from('vocabulary_folders')
        .delete()
        .eq('id', folderId);

      if (error) throw error;

      toast({ title: 'ThÃ nh cÃīng', description: 'ÄÃĢ xÃģa folder' });
      fetchFolders();
    } catch (error) {
      console.error('Error deleting folder:', error);
      toast({
        title: 'Láŧi',
        description: 'KhÃīng tháŧ xÃģa folder',
        variant: 'destructive',
      });
    }
  };

  const openEditDialog = (folder: Folder) => {
    setEditingFolder(folder);
    setParentIdForNew(null);
    setFormData({
      name: folder.name,
      description: folder.description || '',
      icon: folder.icon,
      color: folder.color,
      parent_id: folder.parent_id,
    });
    setIsDialogOpen(true);
  };

  const openCreateChildDialog = (parentId: string) => {
    setEditingFolder(null);
    setParentIdForNew(parentId);
    resetForm();
    setIsDialogOpen(true);
  };

  const resetForm = () => {
    setEditingFolder(null);
    setParentIdForNew(null);
    setFormData({
      name: '',
      description: '',
      icon: 'ð',
      color: '#10b981',
      parent_id: null,
    });
  };

  if (!user) {
    return (
      <div className="min-h-screen bg-background pb-20 md:pb-0">
        <Navigation />
        <main className="container py-6">
