      toast({
        title: 'Láŧi',
        description: error.message || 'KhÃīng tháŧ gáŧ­i tin nhášŊn.',
        variant: 'destructive',
      });
      setConversation(prev => {
        const last = prev[prev.length - 1];
        if (last?.role === 'assistant' && !last.content) {
          return prev.slice(0, -1);
        }
        return prev;
      });
    } finally {
      setIsLoading(false);
    }
  };

