          const s = (seconds % 60).toFixed(3).replace('.', ',');
          return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.padStart(6, '0')}`;
        };
        return `${idx + 1}\n${formatTime(cap.start)} --> ${formatTime(cap.end)}\n${cap.text}\n`;
      }).join('\n');

      setNewVideoSubtitles(srtContent);
      setNewVideoTitle(data.title || '');
      setCaptionLanguage(data.language);

      toast({
        title: 'LášĨy pháŧĨ Äáŧ thÃ nh cÃīng!',
        description: `ÄÃĢ lášĨy ${data.segments_count} ÄoášĄn pháŧĨ Äáŧ (${data.language})`,
      });

    } catch (error: any) {
      console.error('Error fetching captions:', error);
      toast({
        title: 'Láŧi lášĨy pháŧĨ Äáŧ',
        description: error.message || 'KhÃīng tháŧ lášĨy pháŧĨ Äáŧ táŧŦ YouTube',
        variant: 'destructive',
